#include <stdint.h>
#include <stdio.h>

#include "risk_digest.h"

#define POSITION_COUNT 128

/*
 * Approved digest generated by the offline reference implementation in
 * reference_digest.py.
 */
static const uint32_t APPROVED_DIGEST = 0x3512fc5fU;

static void fill_position(Position *position, size_t index) {
  static const char *const regions[] = {"amer", "emea", "apac", "latam"};
  static const char *const books[] = {
      "cash", "macro", "credit", "rates", "equity", "options", "hedge",
  };
  size_t region = (index * 5U + 1U) % 4U;
  size_t book = (index * 3U + 2U) % 7U;

  snprintf(position->id, sizeof(position->id), "pos-%s-%s-%03zu",
           regions[region], books[book], index);
  position->exposure_cents =
      680000U + (uint32_t)((index * 9781U + 137U) % 720000U);
  position->collateral_cents =
      (uint32_t)(((index * 9173U + 2500U) % 7U) * 2500U);
  position->volatility_bp =
      160U + (uint32_t)((index * 251U + 617U) % 3200U);
}

static void load_positions(Position positions[POSITION_COUNT]) {
  for (size_t i = 0; i < POSITION_COUNT; i++) {
    fill_position(&positions[i], i);
  }
}

static int validate_book(const Position *positions, size_t count) {
  uint32_t actual = risk_digest_book(positions, count);
  uint32_t expected = APPROVED_DIGEST;
  int status = actual == expected ? 0 : 1;

  printf("risk_bucket_status=%d actual_digest=%08x expected_digest=%08x "
         "positions=%zu\n",
         status,
         actual,
         expected,
         count);
  return status;
}

int main(void) {
  Position positions[POSITION_COUNT];

  load_positions(positions);
  return validate_book(positions, POSITION_COUNT);
}
